mapper.select:
SELECT COUNT(*)

FROM xeus.crms_prev_rqst




        AND reqst_id LIKE '%'||#{reqstId}||'%'



        AND reqst_id_rel.user_nm LIKE '%'||#{userNm}||'%'



        AND crime_typ = #{crimeTyp}



        AND crimeCtgr = #{crimeTyp}



        AND reqst_dat  >=  #{startDat}



        AND reqst_dat  <=  #{endDat}

SELECT rqst.mgr_seq AS mgr_seq, rqst.reqst_id AS reqst_id, rqst.reqst_dat AS reqst_dat, rqst.proc_stat_cd AS proc_stat_cd, rqst.fnsh_dat AS fnsh_dat
        ,reqst_id_rel.user_nm AS reqst_id_rel_cde_nam, proc_stat_cd_rel.cde_nm AS proc_stat_cd_rel_cde_nam

FROM xeus.crms_prev_rqst AS rqst

LEFT JOIN (
        SELECT crms_user.user_id,
            orgz.org_nm AS office_nm,
            crms_user.user_nm,
            crms_user.depart_nm AS dept_nm,
            crms_user.pos_nm,
            crms_user.tel_num,
            crms_user.auth_stat_cd AS user_stat_cd
        FROM xeus.mt_usr_desc crms_user
        LEFT JOIN xeus.mt_orgz_desc orgz ON orgz.org_mgr_no = crms_user.org_mgr_no
        ) AS reqst_id_rel ON reqst_id_rel.user_id = rqst.reqst_id
LEFT JOIN xeus.mt_cmm_cde AS proc_stat_cd_rel ON proc_stat_cd_rel.grp_cde = 'C52' AND proc_stat_cd_rel.cde_cde = rqst.proc_stat_cd




        AND rqst.mgr_seq = #{mgrSeq}::numeric



        AND rqst.reqst_id LIKE '%'||#{reqstId}||'%'



        AND rqst.reqst_dat = #{reqstDat}



        AND rqst.proc_stat_cd = #{procStatCd}



        AND rqst.fnsh_dat = #{fnshDat}



        AND rqst.reqst_dat  >=  #{startDat}



        AND rqst.reqst_dat  <=  #{endDat}






        ${sortCol} ${sortTyp}


        mgr_seq DESC




    LIMIT ${limit} OFFSET ${offset}

mapper.update:
UPDATE xeus.crms_prev_rqst
SET
    reqst_id = #{reqstId}
    , reqst_dat = #{reqstDat}
    , proc_stat_cd = #{procStatCd}
    , fnsh_dat = #{fnshDat}
WHERE mgr_seq = #{mgrSeq}::numeric
